   304→    /// Inverse transform data from component space back to original space
   305→    pub fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   306→        if !self.is_fitted() {
   307→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   308→        }
   309→        
   310→        // Use base projector for inverse transformation
   311→        let reconstructed = self.base_projector.reconstruct(data)?;
   312→        
   313→        // Apply inverse preprocessing
   314→        if let Some(ref preprocessor) = self.preprocessor {
   315→            preprocessor.inverse_transform(&reconstructed)
   316→        } else {
   317→            Ok(reconstructed)
   318→        }
   319→    }
   320→    
   321→    /// Get the principal components (loadings)
   322→    pub fn components(&self) -> Result<Matrix, MultivariousError> {
   323→        if !self.is_fitted() {
   324→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   325→        }
   326→        
   327→        // Return transpose of projection matrix to match sklearn convention
   328→        Ok(self.base_projector.projection_matrix().t().to_owned())
   329→    }
   330→    
   331→    /// Get singular values
   332→    pub fn singular_values(&self) -> &Vector {
   333→        &self.singular_values
   334→    }
   335→    
   336→    /// Get explained variance ratio
   337→    pub fn explained_variance_ratio(&self) -> &Vector {
   338→        &self.explained_variance_ratio
   339→    }
   340→    
   341→    /// Get cumulative explained variance ratio
   342→    pub fn cumulative_variance_ratio(&self) -> &Vector {
   343→        &self.cumulative_variance_ratio
   344→    }
   345→    
   346→    /// Get total variance explained by selected components
   347→    pub fn total_variance_explained(&self) -> f64 {
   348→        self.explained_variance_ratio.sum()
   349→    }
   350→    
   351→    /// Compute reconstruction error (MSE) for given data
   352→    pub fn reconstruction_error(&self, data: &Matrix) -> Result<f64, MultivariousError> {
   353→        if !self.is_fitted() {
   354→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   355→        }
   356→        
   357→        // Transform and then reconstruct
   358→        let transformed = self.transform(data)?;
   359→        let reconstructed = self.inverse_transform(&transformed)?;
   360→        
   361→        // Compute mean squared error
   362→        let diff = data - &reconstructed;
   363→        let squared_diff = diff.mapv(|x| x * x);
   364→        let mse = squared_diff.mean().unwrap_or(0.0);
   365→        
   366→        Ok(mse)
   367→    }
   368→    
   369→    /// Get explained variance (eigenvalues)
   370→    pub fn explained_variance(&self) -> Result<Vector, MultivariousError> {
   371→        if !self.is_fitted() {
   372→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   373→        }
   374→        
   375→        // Variance is standard deviation squared
   376→        Ok(self.standard_deviations.mapv(|x| x * x))
   377→    }
   378→    
   379→    /// Get the number of components needed to explain a given ratio of variance
   380→    pub fn n_components_for_variance(&self, variance_ratio: f64) -> Result<usize, MultivariousError> {
   381→        if !self.is_fitted() {
   382→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   383→        }
   384→        
   385→        if variance_ratio <= 0.0 || variance_ratio > 1.0 {
   386→            return Err(MultivariousError::InvalidParameter {
   387→                name: "variance_ratio".to_string(),
   388→                value: variance_ratio.to_string(),
   389→                reason: "must be between 0 and 1".to_string(),
   390→            });
   391→        }
   392→        
   393→        // Find first component where cumulative variance >= requested ratio
   394→        for (i, &cum_var) in self.cumulative_variance_ratio.iter().enumerate() {
   395→            if cum_var >= variance_ratio {
   396→                return Ok(i + 1);
   397→            }
   398→        }
   399→        
   400→        // If we get here, all components are needed
   401→        Ok(self.n_components())
   402→    }
   403→    
   404→    /// Apply Kaiser criterion to determine significant components
   405→    /// Components with eigenvalues > 1 are considered significant
   406→    pub fn kaiser_criterion(&self) -> Result<usize, MultivariousError> {
   407→        if !self.is_fitted() {
   408→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   409→        }
   410→        
   411→        if !self.config.use_correlation {
   412→            return Err(MultivariousError::InvalidOperation(
   413→                "Kaiser criterion is only valid for correlation matrix (standardized) PCA".to_string()
   414→            ));
   415→        }
   416→        
   417→        let eigenvalues = self.explained_variance()?;
   418→        let n_significant = eigenvalues.iter()
   419→            .filter(|&&lambda| lambda > 1.0)
   420→            .count();
   421→        
   422→        Ok(n_significant)
   423→    }
   424→    
   425→    /// Compute scree test values (differences between consecutive eigenvalues)
   426→    pub fn scree_values(&self) -> Result<Vector, MultivariousError> {
   427→        if !self.is_fitted() {
   428→            return Err(MultivariousError::NotFitted("PCA".to_string()));
   429→        }
   430→        
   431→        let eigenvalues = self.explained_variance()?;
   432→        
   433→        if eigenvalues.len() < 2 {
   434→            return Ok(Vector::zeros(0));
   435→        }
   436→        
   437→        // Compute differences between consecutive eigenvalues
   438→        let mut scree = Vector::zeros(eigenvalues.len() - 1);
   439→        for i in 0..eigenvalues.len() - 1 {
   440→            scree[i] = eigenvalues[i] - eigenvalues[i + 1];
   441→        }
   442→        
   443→        Ok(scree)
   444→    }
   445→    
   446→    /// Find elbow point in scree plot using simple method
   447→    /// Returns the component index where the eigenvalue differences level off
   448→    pub fn elbow_point(&self) -> Result<usize, MultivariousError> {
   449→        if !self.is_fitted() {
