/// Inverse transform data from component space back to original space
pub fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Use base projector for inverse transformation
    let reconstructed = self.base_projector.reconstruct(data)?;

    // Apply inverse preprocessing
    if let Some(ref preprocessor) = self.preprocessor {
        preprocessor.inverse_transform(&reconstructed)
    } else {
        Ok(reconstructed)
    }
}

/// Get the principal components (loadings)
pub fn components(&self) -> Result<Matrix, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Return transpose of projection matrix to match sklearn convention
    Ok(self.base_projector.projection_matrix().t().to_owned())
}

/// Get singular values
pub fn singular_values(&self) -> &Vector {
    &self.singular_values
}

/// Get explained variance ratio
pub fn explained_variance_ratio(&self) -> &Vector {
    &self.explained_variance_ratio
}

/// Get cumulative explained variance ratio
pub fn cumulative_variance_ratio(&self) -> &Vector {
    &self.cumulative_variance_ratio
}

/// Get total variance explained by selected components
pub fn total_variance_explained(&self) -> f64 {
    self.explained_variance_ratio.sum()
}

/// Compute reconstruction error (MSE) for given data
pub fn reconstruction_error(&self, data: &Matrix) -> Result<f64, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Transform and then reconstruct
    let transformed = self.transform(data)?;
    let reconstructed = self.inverse_transform(&transformed)?;

    // Compute mean squared error
    let diff = data - &reconstructed;
    let squared_diff = diff.mapv(|x| x * x);
    let mse = squared_diff.mean().unwrap_or(0.0);

    Ok(mse)
}

/// Get explained variance (eigenvalues)
pub fn explained_variance(&self) -> Result<Vector, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Variance is standard deviation squared
    Ok(self.standard_deviations.mapv(|x| x * x))
}

/// Get the number of components needed to explain a given ratio of variance
pub fn n_components_for_variance(&self, variance_ratio: f64) -> Result<usize, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    if variance_ratio <= 0.0 || variance_ratio > 1.0 {
        return Err(MultivariousError::InvalidParameter {
            name: "variance_ratio".to_string(),
            value: variance_ratio.to_string(),
            reason: "must be between 0 and 1".to_string(),
        });
    }

    // Find first component where cumulative variance >= requested ratio
    for (i, &cum_var) in self.cumulative_variance_ratio.iter().enumerate() {
        if cum_var >= variance_ratio {
            return Ok(i + 1);
        }
    }

    // If we get here, all components are needed
    Ok(self.n_components())
}

/// Apply Kaiser criterion to determine significant components
/// Components with eigenvalues > 1 are considered significant
pub fn kaiser_criterion(&self) -> Result<usize, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    if !self.config.use_correlation {
        return Err(MultivariousError::InvalidOperation(
            "Kaiser criterion is only valid for correlation matrix (standardized) PCA".to_string()
        ));
    }

    let eigenvalues = self.explained_variance()?;
    let n_significant = eigenvalues.iter()
        .filter(|&&lambda| lambda > 1.0)
        .count();

    Ok(n_significant)
}

/// Compute scree test values (differences between consecutive eigenvalues)
pub fn scree_values(&self) -> Result<Vector, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let eigenvalues = self.explained_variance()?;

    if eigenvalues.len() < 2 {
        return Ok(Vector::zeros(0));
    }

    // Compute differences between consecutive eigenvalues
    let mut scree = Vector::zeros(eigenvalues.len() - 1);
    for i in 0..eigenvalues.len() - 1 {
        scree[i] = eigenvalues[i] - eigenvalues[i + 1];
    }

    Ok(scree)
}

/// Find elbow point in scree plot using simple method
/// Returns the component index where the eigenvalue differences level off
pub fn elbow_point(&self) -> Result<usize, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let scree = self.scree_values()?;

    if scree.is_empty() {
        return Ok(1);
    }

    // Find where the second derivative is minimal (curve flattens)
    if scree.len() < 2 {
        return Ok(1);
    }

    let mut second_diff = Vector::zeros(scree.len() - 1);
    for i in 0..scree.len() - 1 {
        second_diff[i] = scree[i] - scree[i + 1];
    }

    // Find the point where second difference is closest to zero
    let mut min_diff = f64::INFINITY;
    let mut elbow_idx = 0;

    for (i, &diff) in second_diff.iter().enumerate() {
        if diff.abs() < min_diff {
            min_diff = diff.abs();
            elbow_idx = i;
        }
    }

    // Add 2 because we have two levels of differences
    Ok(elbow_idx + 2)
}

/// Get the proportion of variance explained by a subset of components
pub fn variance_explained_by_components(&self, component_indices: &[usize]) -> Result<f64, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let mut total_var = 0.0;
    for &idx in component_indices {
        if idx >= self.explained_variance_ratio.len() {
            return Err(MultivariousError::InvalidParameter {
                name: "component_index".to_string(),
                value: idx.to_string(),
                reason: format!("out of bounds (max: {})", self.explained_variance_ratio.len() - 1),
            });
        }
        total_var += self.explained_variance_ratio[idx];

