    }

    // Transform data to component space
    let scores = self.transform(data)?;
    let n_samples = scores.nrows();

    // Compute T² for each sample
    let mut t2_values = Vector::zeros(n_samples);

    // Get inverse of eigenvalues (1/variance) for weighting
    let eigenvalues = self.explained_variance()?;

    for i in 0..n_samples {
        let sample_scores = scores.row(i);
        let mut t2 = 0.0;

        // T² = sum((score_j)² / eigenvalue_j)
        for j in 0..self.n_components() {
            if eigenvalues[j] > 1e-10 {
                t2 += (sample_scores[j] * sample_scores[j]) / eigenvalues[j];
            }
        }

        t2_values[i] = t2;
    }

    Ok(t2_values)
}

/// Compute Q-residuals (squared prediction error) for outlier detection
pub fn q_residuals(&self, data: &Matrix) -> Result<Vector, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Transform and reconstruct
    let transformed = self.transform(data)?;
    let reconstructed = self.inverse_transform(&transformed)?;

    // Compute squared residuals for each sample
    let n_samples = data.nrows();
    let mut q_values = Vector::zeros(n_samples);

    for i in 0..n_samples {
        let residual = &data.row(i) - &reconstructed.row(i);
        q_values[i] = residual.dot(&residual);
    }

    Ok(q_values)
}

/// Compute contribution of each variable to each principal component
pub fn variable_contributions(&self) -> Result<Matrix, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let components = self.components()?;
    let n_components = components.nrows();
    let n_features = components.ncols();

    // Contribution = squared loading / sum of squared loadings for that component
    let mut contributions = Matrix::zeros((n_components, n_features));

    for i in 0..n_components {
        let component = components.row(i);
        let sum_sq = component.dot(&component);

        if sum_sq > 1e-10 {
            for j in 0..n_features {
                contributions[[i, j]] = (component[j] * component[j]) / sum_sq;
            }
        }
    }

    Ok(contributions)
}

/// Compute contribution of each sample to each principal component
pub fn sample_contributions(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let scores = self.transform(data)?;
    let n_samples = scores.nrows();
    let n_components = scores.ncols();

    // Contribution = squared score / (n_samples * eigenvalue)
    let eigenvalues = self.explained_variance()?;
    let mut contributions = Matrix::zeros((n_samples, n_components));

    for j in 0..n_components {
        if eigenvalues[j] > 1e-10 {
            let scale = (n_samples as f64) * eigenvalues[j];
            for i in 0..n_samples {
                contributions[[i, j]] = (scores[[i, j]] * scores[[i, j]]) / scale;
            }
        }
    }

    Ok(contributions)
}

/// Apply rotation to the principal components
/// 
/// This method rotates the loadings matrix to improve interpretability.
/// The rotation can be orthogonal (e.g., Varimax, Quartimax) or oblique (e.g., Promax).
/// 
/// # Arguments
/// * `rotation` - The rotation method to apply
/// 
/// # Returns
/// * `RotationResult` containing the rotated loadings and rotation matrix
pub fn rotate<R: super::rotation::Rotation>(&self, rotation: &R) -> Result<super::rotation::RotationResult, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Get the loadings matrix (components)
    let loadings = self.components()?;

    // Apply the rotation
    rotation.rotate(&loadings.t().to_owned())
}

/// Apply rotation and update the PCA model with rotated components
/// 
/// This method rotates the components and updates the internal state of the PCA model.
/// Note: After rotation, some properties like explained variance ratios may change
/// for oblique rotations.
/// 
/// # Arguments
/// * `rotation` - The rotation method to apply
pub fn rotate_in_place<R: super::rotation::Rotation>(&mut self, rotation: &R) -> Result<(), MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    // Get the rotation result
    let rotation_result = self.rotate(rotation)?;

    // Update the base projector with rotated components
    // Note: We need to transpose back since components are stored as columns
    let rotated_components = rotation_result.rotated_loadings.t().to_owned();

    // Update the existing base projector with the rotated components
    self.base_projector.set_projection_matrix(rotated_components)?;

    // If rotation is oblique, we need to handle it differently
    if !rotation_result.is_orthogonal {
        // For oblique rotations, the explained variance interpretation changes
        // We should add a warning or handle this case specially
        log::warn!("Oblique rotation applied. Explained variance ratios may no longer be directly interpretable.");
    }

    Ok(())
}

/// Get the scores (transformed data) for the fitted model
/// 
/// This is equivalent to calling `transform` on the training data
/// but may be more efficient if the scores were cached during fitting.
pub fn scores(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    self.transform(data)
}

/// Compute influence measures for observations
/// 
/// Returns a matrix where each row contains:
/// - Column 0: Leverage (hat values)
/// - Column 1: Cook's distance
/// - Column 2: DFFITS
/// 
/// These measures help identify influential observations that have a large effect
/// on the PCA model.
pub fn influence_measures(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    if !self.is_fitted() {
        return Err(MultivariousError::NotFitted("PCA".to_string()));
    }

    let n_samples = data.nrows();
    let scores = self.transform(data)?;
    let eigenvalues = self.explained_variance()?;

    // Initialize result matrix
    let mut measures = Matrix::zeros((n_samples, 3));

    // Compute leverage (hat values) for each observation
    // h_i = sum(score_ij^2 / (n * eigenvalue_j))
    for i in 0..n_samples {
        let mut leverage = 0.0;
        for j in 0..self.n_components() {
            if eigenvalues[j] > 1e-10 {
                leverage += (scores[[i, j]] * scores[[i, j]]) / ((n_samples as f64) * eigenvalues[j]);
            }
        }
        measures[[i, 0]] = leverage;
    }

    // Compute residuals for Cook's distance and DFFITS
    let q_residuals = self.q_residuals(data)?;
    let mean_q = q_residuals.mean().unwrap_or(0.0);

    // Estimate residual variance
    let mut residual_variance = 0.0;
    for i in 0..n_samples {
        residual_variance += (q_residuals[i] - mean_q).powi(2);
    }
    residual_variance /= (n_samples - self.n_components() - 1) as f64;

    // Compute Cook's distance and DFFITS
    for i in 0..n_samples {
        let leverage = measures[[i, 0]];

