    /// Compute model fit statistics
    /// 
    /// Returns a struct containing various fit statistics:
    /// - Total variance explained
    /// - Residual sum of squares (RSS)
    /// - R-squared value
    /// - Adjusted R-squared
    /// - Root mean square error (RMSE)
    /// - Akaike Information Criterion (AIC)
    /// - Bayesian Information Criterion (BIC)
    pub fn fit_statistics(&self, data: &Matrix) -> Result<PcaFitStatistics, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let n_samples = data.nrows();
        let n_features = data.ncols();
        let n_components = self.n_components();

        // Compute residuals
        let transformed = self.transform(data)?;
        let reconstructed = self.inverse_transform(&transformed)?;
        let residuals = data - &reconstructed;

        // Residual sum of squares
        let rss = residuals.iter().map(|&x| x * x).sum::<f64>();

        // Total sum of squares (using preprocessed data)
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        let mut tss = 0.0;
        for j in 0..n_features {
            let col_mean = preprocessed.column(j).mean().unwrap_or(0.0);
            for i in 0..n_samples {
                let diff = preprocessed[[i, j]] - col_mean;
                tss += diff * diff;
            }
        }

        // R-squared
        let r_squared = if tss > 1e-10 { 1.0 - (rss / tss) } else { 0.0 };

        // Adjusted R-squared
        let df_resid = (n_samples * n_features - n_components * (n_samples + n_features)) as f64;
        let df_total = (n_samples * n_features - 1) as f64;
        let adj_r_squared = if df_total > 0.0 && df_resid > 0.0 {
            1.0 - ((1.0 - r_squared) * df_total / df_resid)
        } else {
            r_squared
        };

        // Root mean square error
        let rmse = (rss / (n_samples * n_features) as f64).sqrt();

        // Log-likelihood for AIC/BIC (assuming Gaussian errors)
        let sigma_squared = rss / (n_samples * n_features) as f64;
        let log_likelihood = -0.5 * (n_samples * n_features) as f64 * 
                            (1.0 + (2.0 * std::f64::consts::PI * sigma_squared).ln());

        // Number of parameters: components * (samples + features)
        let n_params = n_components * (n_samples + n_features);

        // AIC = 2k - 2ln(L)
        let aic = 2.0 * n_params as f64 - 2.0 * log_likelihood;

        // BIC = ln(n)*k - 2ln(L)
        let bic = (n_samples * n_features) as f64 * n_params as f64 - 2.0 * log_likelihood;

        Ok(PcaFitStatistics {
            total_variance_explained: self.total_variance_explained(),
            residual_sum_of_squares: rss,
            r_squared,
            adjusted_r_squared: adj_r_squared,
            rmse,
            aic,
            bic,
            n_components,
            n_samples,
            n_features,
        })
    }
}

// Implement projection traits
impl Project for Pca {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.transform(data)
    }

    fn n_components(&self) -> usize {
        self.base_projector.n_components()
    }

    fn n_features(&self) -> usize {
        self.base_projector.n_features()
    }

    fn is_fitted(&self) -> bool {
        self.base_projector.is_fitted()
    }

    fn name(&self) -> &str {
        "PCA"
    }
}

impl Reconstruct for Pca {
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
        self.inverse_transform(projected)
    }
}

impl PartialProject for Pca {
    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Apply preprocessing
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        // Use base projector for partial projection
        self.base_projector.project_components(&preprocessed, component_indices)
    }

    fn component_importance(&self) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        Ok(self.explained_variance_ratio.clone())
    }
}

impl fmt::Display for Pca {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        if self.is_fitted() {
            write!(
                f,
                "PCA(n_components={}, n_features={}, method={:?}, variance_explained={:.2}%)",
                self.n_components(),
                self.n_features(),
                self.svd_method,
                self.total_variance_explained() * 100.0
            )
        } else {
            write!(f, "PCA(unfitted)")
        }
    }
}

/// Builder for PCA
#[derive(Debug, Clone)]
pub struct PcaBuilder {
    config: PcaConfig,
}

impl PcaBuilder {
    pub fn new() -> Self {
        Self {
            config: PcaConfig::default(),
        }
    }

    /// Set the number of components
    pub fn n_components(mut self, n: usize) -> Self {
        self.config.projector_config.n_components = Some(n);
        self
    }

    /// Set minimum variance to retain
    pub fn min_variance(mut self, ratio: f64) -> Self {
        self.config.min_variance_retained = Some(ratio);
        self
    }

    /// Use correlation matrix instead of covariance
    pub fn use_correlation(mut self, use_corr: bool) -> Self {
        self.config.use_correlation = use_corr;
        self
    }

    /// Set SVD method
    pub fn svd_method(mut self, method: SvdMethod) -> Self {
        self.config.svd_method = method;
        self
    }

    /// Set whether to center data
    pub fn center(mut self, center: bool) -> Self {
        self.config.projector_config.center = center;
        self
    }

    /// Set whether to scale data
    pub fn scale(mut self, scale: bool) -> Self {
        self.config.projector_config.scale = scale;
        self
    }

    /// Set random state for reproducibility
    pub fn random_state(mut self, seed: u64) -> Self {
        self.config.projector_config.random_state = Some(seed);
        self.config.svd_config.random_state = Some(seed);
        self
    }

    /// Build the PCA instance
    pub fn build(self) -> Pca {
        Pca::new(self.config)
    }
}

impl Default for PcaBuilder {
    fn default() -> Self {
        Self::new()
    }
}

