            [3.0, 4.0, 0.1],
            [0.1, 0.2, 3.0],
            [0.2, 0.1, 4.0],
        ]);

        // Fit PCA
        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();
        pca.fit(&data).unwrap();

        // Get original components
        let original_components = pca.components().unwrap();

        // Apply rotation in place
        let rotation = QuartimaxRotation::new();
        pca.rotate_in_place(&rotation).unwrap();

        // Get rotated components
        let rotated_components = pca.components().unwrap();

        // Components should be different after rotation
        let diff = &original_components - &rotated_components;
        let max_diff = diff.iter().map(|&x| x.abs()).fold(0.0, f64::max);
        assert!(max_diff > 0.01);

        // Transform should still work
        let transformed = pca.transform(&data).unwrap();
        assert_eq!(transformed.dim(), (5, 2));
    }

