//! Component rotation methods for PCA
//! 
//! This module provides various rotation methods to improve interpretability
//! of principal components. Rotations can be orthogonal (preserving orthogonality)
//! or oblique (allowing correlated components).

use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use serde::{Serialize, Deserialize};

/// Result of a rotation operation
#[derive(Debug, Clone)]
pub struct RotationResult {
    /// Rotated loadings matrix
    pub rotated_loadings: Matrix,

    /// Rotation matrix applied
    pub rotation_matrix: Matrix,

    /// Number of iterations (if iterative method)
    pub iterations: Option<usize>,

    /// Final convergence criterion value
    pub convergence_value: Option<f64>,

    /// Whether the rotation is orthogonal
    pub is_orthogonal: bool,
}

/// Trait for all rotation methods
pub trait Rotation: Send + Sync {
    /// Rotate the loadings matrix
    fn rotate(&self, loadings: &Matrix) -> Result<RotationResult, MultivariousError>;

    /// Check if the rotation is orthogonal
    fn is_orthogonal(&self) -> bool;

    /// Get the name of the rotation method
    fn name(&self) -> &str;
}

/// Trait for orthogonal rotations (preserving orthogonality)
pub trait OrthogonalRotation: Rotation {
    /// Verify that the rotation matrix is orthogonal
    fn verify_orthogonality(&self, rotation_matrix: &Matrix) -> Result<(), MultivariousError> {
        let n = rotation_matrix.ncols();
        if rotation_matrix.nrows() != n {
            return Err(MultivariousError::DimensionMismatch {
                expected: format!("{}x{}", n, n),
                actual: format!("{}x{}", rotation_matrix.nrows(), rotation_matrix.ncols()),
            });
        }

        // Check R^T * R = I
        let rtm = rotation_matrix.t().dot(rotation_matrix);
        for i in 0..n {
            for j in 0..n {
                let expected = if i == j { 1.0 } else { 0.0 };
                let actual = rtm[[i, j]];
                if (actual - expected).abs() > 1e-10 {
                    return Err(MultivariousError::ValidationError {
                        message: format!("Rotation matrix is not orthogonal: R^T*R[{},{}] = {} (expected {})", 
                                i, j, actual, expected)
                    });
                }
            }
        }
        Ok(())
    }
}

/// Configuration for iterative rotation methods
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RotationConfig {
    /// Maximum number of iterations
    pub max_iter: usize,

    /// Convergence tolerance
    pub tolerance: f64,

    /// Whether to normalize rows during rotation
    pub normalize: bool,
}

impl Default for RotationConfig {
    fn default() -> Self {
        Self {
            max_iter: 1000,
            tolerance: 1e-6,
            normalize: true,
        }
    }
}

// Re-export specific rotation methods
mod varimax;
mod quartimax;
mod equamax;
mod promax;

pub use varimax::VarimaxRotation;
pub use quartimax::QuartimaxRotation;
pub use equamax::EquamaxRotation;
pub use promax::PromaxRotation;

