use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use crate::projector::{
    traits::{Project, Reconstruct, PartialProject, ProjectorConfig},
    BaseProjector,
};
use crate::preprocessing::{Preprocessor, Center, Standardize, PreprocessPipeline};
use crate::svd::{SvdMethod, SvdConfig, svd_factory};
use serde::{Serialize, Deserialize};
use std::fmt;

/// Component selection criterion for automatic selection
#[derive(Debug, Clone, Copy)]
pub enum ComponentSelectionCriterion {
    /// Keep components that explain at least this fraction of total variance
    VarianceThreshold(f64),
    /// Kaiser criterion - keep components with eigenvalue > 1 (for correlation PCA)
    Kaiser,
    /// Elbow method - find the elbow point in the scree plot
    Elbow,
    /// Fixed number of components
    FixedNumber(usize),
}

/// PCA model fit statistics
#[derive(Debug, Clone)]
pub struct PcaFitStatistics {
    /// Total variance explained by the model
    pub total_variance_explained: f64,
    /// Residual sum of squares
    pub residual_sum_of_squares: f64,
    /// R-squared value
    pub r_squared: f64,
    /// Adjusted R-squared
    pub adjusted_r_squared: f64,
    /// Root mean square error
    pub rmse: f64,
    /// Akaike Information Criterion
    pub aic: f64,
    /// Bayesian Information Criterion
    pub bic: f64,
    /// Number of components
    pub n_components: usize,
    /// Number of samples
    pub n_samples: usize,
    /// Number of features
    pub n_features: usize,
}

/// Principal Component Analysis (PCA)
/// 
/// PCA is a statistical procedure that uses an orthogonal transformation to convert
/// a set of observations of possibly correlated variables into a set of values of
/// linearly uncorrelated variables called principal components.
/// 
/// This implementation provides functionality equivalent to R's `prcomp()` function,
/// with additional features for component selection, rotation, and diagnostics.
/// 
/// # Mathematical Background
/// 
/// PCA performs eigendecomposition on the covariance (or correlation) matrix:
/// - Covariance mode: `cov(X) = X'X / (n-1)` where X is centered
/// - Correlation mode: Uses standardized data (mean=0, sd=1)
/// 
/// The principal components are the eigenvectors of this matrix, ordered by
/// their corresponding eigenvalues (amount of variance explained).
/// 
/// # Examples
/// 
/// ## Basic usage (equivalent to R's prcomp)
/// ```
/// use multivarious::pca::{Pca, PcaBuilder};
/// use ndarray::array;
/// 
/// let data = array![
///     [2.5, 2.4],
///     [0.5, 0.7],
///     [2.2, 2.9],
///     [1.9, 2.2],
///     [3.1, 3.0],
/// ];
/// 
/// // Equivalent to R: prcomp(data, center = TRUE, scale. = FALSE)
/// let mut pca = PcaBuilder::new()
///     .use_correlation(false)  // Use covariance matrix
///     .build();
/// 
/// pca.fit(&data).unwrap();
/// 
/// // Get principal components (loadings)
/// let components = pca.components().unwrap();
/// 
/// // Get scores (transformed data)
/// let scores = pca.transform(&data).unwrap();
/// 
/// // Get standard deviations (sqrt of eigenvalues)
/// let sdev = pca.standard_deviations();
/// ```
/// 
/// ## Using correlation matrix (standardized PCA)
/// ```
/// # use multivarious::pca::{Pca, PcaBuilder};
/// # use ndarray::array;
/// # let data = array![[2.5, 2.4], [0.5, 0.7], [2.2, 2.9]];
/// // Equivalent to R: prcomp(data, center = TRUE, scale. = TRUE)
/// let mut pca = PcaBuilder::new()
///     .use_correlation(true)  // Standardize variables
///     .build();
/// ```
/// 
/// ## Selecting number of components
/// ```
/// # use multivarious::pca::{Pca, PcaBuilder, ComponentSelectionCriterion};
/// # use ndarray::array;
/// # let data = array![[2.5, 2.4], [0.5, 0.7], [2.2, 2.9]];
/// // Keep components explaining 95% of variance
/// let mut pca = PcaBuilder::new()
///     .min_variance(0.95)
///     .build();
/// 
/// // Or use automatic selection after fitting
/// let mut pca2 = PcaBuilder::new().build();
/// pca2.fit(&data).unwrap();
/// pca2.auto_select_components(ComponentSelectionCriterion::Kaiser).unwrap();
/// ```
/// 
/// # R Compatibility
/// 
/// | R Function | Rust Equivalent |
/// |------------|-----------------|
/// | `prcomp(x)` | `PcaBuilder::new().build()` |
/// | `prcomp(x, scale. = TRUE)` | `PcaBuilder::new().use_correlation(true).build()` |
/// | `predict(pca, newdata)` | `pca.transform(newdata)` |
/// | `pca$rotation` | `pca.components()` |
/// | `pca$x` | `pca.transform(training_data)` |
/// | `pca$sdev` | `pca.standard_deviations()` |
/// | `summary(pca)` | `pca.explained_variance_ratio()` |
#[derive(Debug, Clone)]
pub struct Pca {
    /// Base projector containing the projection matrix
    base_projector: BaseProjector,

    /// Singular values from SVD
    singular_values: Vector,

    /// Standard deviations of components
    standard_deviations: Vector,

    /// Explained variance ratio for each component
    explained_variance_ratio: Vector,

    /// Cumulative explained variance ratio
    cumulative_variance_ratio: Vector,

    /// Total variance in the original data
    total_variance: f64,

    /// Number of samples used for fitting
    n_samples: usize,

    /// Preprocessing pipeline
    preprocessor: Option<PreprocessPipeline>,

    /// SVD method used
    svd_method: SvdMethod,

    /// Configuration
    config: PcaConfig,
}

/// Configuration for PCA
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PcaConfig {
    /// Base projector configuration
    pub projector_config: ProjectorConfig,

    /// SVD method to use
    pub svd_method: SvdMethod,

    /// SVD configuration
    pub svd_config: SvdConfig,

    /// Whether to use correlation matrix (standardize) or covariance matrix (center only)
    pub use_correlation: bool,

    /// Minimum variance to retain (between 0 and 1)
    pub min_variance_retained: Option<f64>,

    /// Whether to compute all components or just the requested number
    pub compute_all_components: bool,
}

impl Default for PcaConfig {
    fn default() -> Self {
        Self {
            projector_config: ProjectorConfig::default(),
            svd_method: SvdMethod::Auto,
            svd_config: SvdConfig::default(),
            use_correlation: false,
            min_variance_retained: None,
            compute_all_components: false,
        }
    }
}

impl Pca {
    /// Create a new unfitted PCA instance
    pub fn new(config: PcaConfig) -> Self {
        let n_features = 0;
        let n_components = config.projector_config.n_components.unwrap_or(0);

        Self {
            base_projector: BaseProjector::new_unfitted(n_features, n_components, config.projector_config.clone()),
            singular_values: Vector::zeros(0),
            standard_deviations: Vector::zeros(0),
            explained_variance_ratio: Vector::zeros(0),
            cumulative_variance_ratio: Vector::zeros(0),
            total_variance: 0.0,
            n_samples: 0,
            preprocessor: None,
            svd_method: config.svd_method,
            config,
        }
    }

    /// Fit the PCA model to data
    pub fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let (n_samples, n_features) = data.dim();

        if n_samples < 2 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_samples".to_string(),
                value: n_samples.to_string(),
                reason: "PCA requires at least 2 samples".to_string(),
            });
        }

        if n_features < 1 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_features".to_string(),
                value: n_features.to_string(),
                reason: "PCA requires at least 1 feature".to_string(),
            });
        }

        self.n_samples = n_samples;

        // Set up preprocessing
        let mut pipeline = PreprocessPipeline::new();

        if self.config.use_correlation {
            // Standardize (mean=0, std=1)
            pipeline = pipeline.add_step(Box::new(Standardize::new()));
        } else {
            // Just center (mean=0)
            pipeline = pipeline.add_step(Box::new(Center::new()));
        }

        // Fit and transform the data
        let preprocessed = pipeline.fit_transform(data)?;
        self.preprocessor = Some(pipeline);

        // Determine number of components
        let max_components = n_features.min(n_samples - 1);
        let n_components = if let Some(n) = self.config.projector_config.n_components {
            n.min(max_components)
        } else if let Some(_min_var) = self.config.min_variance_retained {
            // Will determine after SVD
            max_components
        } else {
            max_components
        };

        // Configure SVD
        let mut svd_config = self.config.svd_config.clone();
        svd_config.n_components = Some(n_components);

        // Select SVD method
        let svd_method = if self.config.svd_method == SvdMethod::Auto {
            // Auto-select based on matrix size
            if n_samples * n_features < 1000 {
                SvdMethod::Full
            } else if n_components < max_components / 2 {
                SvdMethod::Truncated(n_components)
            } else {
                SvdMethod::Full
            }
        } else {
            self.config.svd_method
        };

        // Create SVD solver
        let solver = svd_factory(svd_method, svd_config)?;

        // Compute SVD
        let svd_result = solver.compute(&preprocessed)?;

        // Store singular values and compute variance explained
        self.singular_values = svd_result.singular_values.clone();

        // Standard deviations are singular values scaled by sqrt(n-1)
        let scale_factor = (n_samples - 1) as f64;
        self.standard_deviations = &self.singular_values / scale_factor.sqrt();

        // Compute explained variance ratio
        let variances = self.standard_deviations.mapv(|x| x * x);
        self.total_variance = variances.sum();

        if self.total_variance > 0.0 {
            self.explained_variance_ratio = &variances / self.total_variance;
        } else {
            self.explained_variance_ratio = Vector::zeros(variances.len());
        }

        // Compute cumulative variance ratio
        self.cumulative_variance_ratio = Vector::zeros(self.explained_variance_ratio.len());
        let mut cumsum = 0.0;
        for (i, &ratio) in self.explained_variance_ratio.iter().enumerate() {
            cumsum += ratio;
            self.cumulative_variance_ratio[i] = cumsum;
        }

        // Determine final number of components if using min_variance_retained
        let final_n_components = if let Some(min_var) = self.config.min_variance_retained {
            // Find the number of components that explain at least min_var of variance
            let n = self.cumulative_variance_ratio
                .iter()
                .position(|&x| x >= min_var)
                .map(|i| i + 1)
                .unwrap_or(n_components);
            n.min(n_components)
        } else {
            n_components
        };

        // Extract the components (V^T from SVD)
        let components = if let Some(vt) = svd_result.vt {
            vt.slice(ndarray::s![..final_n_components, ..]).to_owned()
        } else {
            return Err(MultivariousError::ComputationError(
                "SVD did not return V^T matrix".to_string()
            ));
        };

        // Create projection matrix (transpose of components for our convention)
        let projection_matrix = components.t().to_owned();

        // Update base projector
        self.base_projector = BaseProjector::new(projection_matrix, self.config.projector_config.clone())?;

        // Truncate variance arrays if needed
        if final_n_components < self.singular_values.len() {
            self.singular_values = self.singular_values.slice(ndarray::s![..final_n_components]).to_owned();
            self.standard_deviations = self.standard_deviations.slice(ndarray::s![..final_n_components]).to_owned();
            self.explained_variance_ratio = self.explained_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
            self.cumulative_variance_ratio = self.cumulative_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
        }

        self.svd_method = svd_method;

        Ok(())
    }

    /// Fit the model and transform the data in one step
    pub fn fit_transform(&mut self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.fit(data)?;
        self.transform(data)
    }

    /// Transform data using the fitted PCA model
    pub fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Apply preprocessing
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        // Use base projector for transformation
        self.base_projector.project(&preprocessed)
    }

    /// Inverse transform data from component space back to original space
    pub fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Use base projector for inverse transformation
        let reconstructed = self.base_projector.reconstruct(data)?;

        // Apply inverse preprocessing
        if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.inverse_transform(&reconstructed)
        } else {
            Ok(reconstructed)
        }
    }

    /// Get the principal components (loadings)
    pub fn components(&self) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Return transpose of projection matrix to match sklearn convention
        Ok(self.base_projector.projection_matrix().t().to_owned())
    }

    /// Get singular values
    pub fn singular_values(&self) -> &Vector {
        &self.singular_values
    }

    /// Get explained variance ratio
    pub fn explained_variance_ratio(&self) -> &Vector {
        &self.explained_variance_ratio
    }

    /// Get cumulative explained variance ratio
    pub fn cumulative_variance_ratio(&self) -> &Vector {
        &self.cumulative_variance_ratio
    }

    /// Get total variance explained by selected components
    pub fn total_variance_explained(&self) -> f64 {
        self.explained_variance_ratio.sum()
    }

    /// Compute reconstruction error (MSE) for given data
    pub fn reconstruction_error(&self, data: &Matrix) -> Result<f64, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Transform and then reconstruct
        let transformed = self.transform(data)?;
        let reconstructed = self.inverse_transform(&transformed)?;

        // Compute mean squared error
        let diff = data - &reconstructed;
        let squared_diff = diff.mapv(|x| x * x);
        let mse = squared_diff.mean().unwrap_or(0.0);

        Ok(mse)
    }

    /// Get explained variance (eigenvalues)
    pub fn explained_variance(&self) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Variance is standard deviation squared
        Ok(self.standard_deviations.mapv(|x| x * x))
    }

    /// Get the number of components needed to explain a given ratio of variance
    pub fn n_components_for_variance(&self, variance_ratio: f64) -> Result<usize, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        if variance_ratio <= 0.0 || variance_ratio > 1.0 {
            return Err(MultivariousError::InvalidParameter {
                name: "variance_ratio".to_string(),
                value: variance_ratio.to_string(),
                reason: "must be between 0 and 1".to_string(),
            });
        }

        // Find first component where cumulative variance >= requested ratio
        for (i, &cum_var) in self.cumulative_variance_ratio.iter().enumerate() {
            if cum_var >= variance_ratio {
                return Ok(i + 1);
            }
        }

        // If we get here, all components are needed
        Ok(self.n_components())
    }

    /// Apply Kaiser criterion to determine significant components
    /// Components with eigenvalues > 1 are considered significant
    pub fn kaiser_criterion(&self) -> Result<usize, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        if !self.config.use_correlation {
            return Err(MultivariousError::InvalidOperation(
                "Kaiser criterion is only valid for correlation matrix (standardized) PCA".to_string()
            ));
        }

        let eigenvalues = self.explained_variance()?;
        let n_significant = eigenvalues.iter()
            .filter(|&&lambda| lambda > 1.0)
            .count();

        Ok(n_significant)
    }

    /// Compute scree test values (differences between consecutive eigenvalues)
    pub fn scree_values(&self) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let eigenvalues = self.explained_variance()?;

        if eigenvalues.len() < 2 {
            return Ok(Vector::zeros(0));
        }

        // Compute differences between consecutive eigenvalues
        let mut scree = Vector::zeros(eigenvalues.len() - 1);
        for i in 0..eigenvalues.len() - 1 {
            scree[i] = eigenvalues[i] - eigenvalues[i + 1];
        }

        Ok(scree)
    }

    /// Find elbow point in scree plot using simple method
    /// Returns the component index where the eigenvalue differences level off
    pub fn elbow_point(&self) -> Result<usize, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let scree = self.scree_values()?;

        if scree.is_empty() {
            return Ok(1);
        }

        // Find where the second derivative is minimal (curve flattens)
        if scree.len() < 2 {
            return Ok(1);
        }

        let mut second_diff = Vector::zeros(scree.len() - 1);
        for i in 0..scree.len() - 1 {
            second_diff[i] = scree[i] - scree[i + 1];
        }

        // Find the point where second difference is closest to zero
        let mut min_diff = f64::INFINITY;
        let mut elbow_idx = 0;

        for (i, &diff) in second_diff.iter().enumerate() {
            if diff.abs() < min_diff {
                min_diff = diff.abs();
                elbow_idx = i;
            }
        }

        // Add 2 because we have two levels of differences
        Ok(elbow_idx + 2)
    }

    /// Get the proportion of variance explained by a subset of components
    pub fn variance_explained_by_components(&self, component_indices: &[usize]) -> Result<f64, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let mut total_var = 0.0;
        for &idx in component_indices {
            if idx >= self.explained_variance_ratio.len() {
                return Err(MultivariousError::InvalidParameter {
                    name: "component_index".to_string(),
                    value: idx.to_string(),
                    reason: format!("out of bounds (max: {})", self.explained_variance_ratio.len() - 1),
                });
            }
            total_var += self.explained_variance_ratio[idx];
        }

        Ok(total_var)
    }

    /// Get standard deviations of components
    pub fn standard_deviations(&self) -> &Vector {
        &self.standard_deviations
    }

    /// Get total variance in the original data
    pub fn total_variance(&self) -> f64 {
        self.total_variance
    }

    /// Truncate PCA to retain only the first k components
    pub fn truncate(&mut self, k: usize) -> Result<(), MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        if k == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "k".to_string(),
                value: k.to_string(),
                reason: "must be at least 1".to_string(),
            });
        }

        if k > self.n_components() {
            return Err(MultivariousError::InvalidParameter {
                name: "k".to_string(),
                value: k.to_string(),
                reason: format!("exceeds current number of components ({})", self.n_components()),
            });
        }

        if k == self.n_components() {
            return Ok(()); // Nothing to truncate
        }

        // Truncate the projection matrix
        let projection_matrix = self.base_projector.projection_matrix();
        let truncated_matrix = projection_matrix.slice(ndarray::s![.., ..k]).to_owned();

        // Create new base projector with truncated matrix
        self.base_projector = BaseProjector::new(truncated_matrix, self.config.projector_config.clone())?;

        // Truncate variance arrays
        self.singular_values = self.singular_values.slice(ndarray::s![..k]).to_owned();
        self.standard_deviations = self.standard_deviations.slice(ndarray::s![..k]).to_owned();
        self.explained_variance_ratio = self.explained_variance_ratio.slice(ndarray::s![..k]).to_owned();
        self.cumulative_variance_ratio = self.cumulative_variance_ratio.slice(ndarray::s![..k]).to_owned();

        Ok(())
    }

    /// Automatically select the number of components based on a selection criterion
    pub fn auto_select_components(&mut self, criterion: ComponentSelectionCriterion) -> Result<usize, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let n_components = match criterion {
            ComponentSelectionCriterion::VarianceThreshold(threshold) => {
                self.n_components_for_variance(threshold)?
            }
            ComponentSelectionCriterion::Kaiser => {
                self.kaiser_criterion()?
            }
            ComponentSelectionCriterion::Elbow => {
                self.elbow_point()?
            }
            ComponentSelectionCriterion::FixedNumber(n) => {
                n.min(self.n_components())
            }
        };

        self.truncate(n_components)?;
        Ok(n_components)
    }

    /// Compute Hotelling's T-squared statistic for outlier detection
    pub fn hotelling_t2(&self, data: &Matrix) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Transform data to component space
        let scores = self.transform(data)?;
        let n_samples = scores.nrows();

        // Compute T² for each sample
        let mut t2_values = Vector::zeros(n_samples);

        // Get inverse of eigenvalues (1/variance) for weighting
        let eigenvalues = self.explained_variance()?;

        for i in 0..n_samples {
            let sample_scores = scores.row(i);
            let mut t2 = 0.0;

            // T² = sum((score_j)² / eigenvalue_j)
            for j in 0..self.n_components() {
                if eigenvalues[j] > 1e-10 {
                    t2 += (sample_scores[j] * sample_scores[j]) / eigenvalues[j];
                }
            }

            t2_values[i] = t2;
        }

        Ok(t2_values)
    }

    /// Compute Q-residuals (squared prediction error) for outlier detection
    pub fn q_residuals(&self, data: &Matrix) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Transform and reconstruct
        let transformed = self.transform(data)?;
        let reconstructed = self.inverse_transform(&transformed)?;

        // Compute squared residuals for each sample
        let n_samples = data.nrows();
        let mut q_values = Vector::zeros(n_samples);

        for i in 0..n_samples {
            let residual = &data.row(i) - &reconstructed.row(i);
            q_values[i] = residual.dot(&residual);
        }

        Ok(q_values)
    }

    /// Compute contribution of each variable to each principal component
    pub fn variable_contributions(&self) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let components = self.components()?;
        let n_components = components.nrows();
        let n_features = components.ncols();

        // Contribution = squared loading / sum of squared loadings for that component
        let mut contributions = Matrix::zeros((n_components, n_features));

        for i in 0..n_components {
            let component = components.row(i);
            let sum_sq = component.dot(&component);

            if sum_sq > 1e-10 {
                for j in 0..n_features {
                    contributions[[i, j]] = (component[j] * component[j]) / sum_sq;
                }
            }
        }

        Ok(contributions)
    }

    /// Compute contribution of each sample to each principal component
    pub fn sample_contributions(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let scores = self.transform(data)?;
        let n_samples = scores.nrows();
        let n_components = scores.ncols();

        // Contribution = squared score / (n_samples * eigenvalue)
        let eigenvalues = self.explained_variance()?;
        let mut contributions = Matrix::zeros((n_samples, n_components));

        for j in 0..n_components {
            if eigenvalues[j] > 1e-10 {
                let scale = (n_samples as f64) * eigenvalues[j];
                for i in 0..n_samples {
                    contributions[[i, j]] = (scores[[i, j]] * scores[[i, j]]) / scale;
                }
            }
        }

        Ok(contributions)
    }

    /// Apply rotation to the principal components
    /// 
    /// This method rotates the loadings matrix to improve interpretability.
    /// The rotation can be orthogonal (e.g., Varimax, Quartimax) or oblique (e.g., Promax).
    /// 
    /// # Arguments
    /// * `rotation` - The rotation method to apply
    /// 
    /// # Returns
    /// * `RotationResult` containing the rotated loadings and rotation matrix
    pub fn rotate<R: super::rotation::Rotation>(&self, rotation: &R) -> Result<super::rotation::RotationResult, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Get the loadings matrix (components)
        let loadings = self.components()?;

        // Apply the rotation
        rotation.rotate(&loadings.t().to_owned())
    }

    /// Apply rotation and update the PCA model with rotated components
    /// 
    /// This method rotates the components and updates the internal state of the PCA model.
    /// Note: After rotation, some properties like explained variance ratios may change
    /// for oblique rotations.
    /// 
    /// # Arguments
    /// * `rotation` - The rotation method to apply
    pub fn rotate_in_place<R: super::rotation::Rotation>(&mut self, rotation: &R) -> Result<(), MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Get the rotation result
        let rotation_result = self.rotate(rotation)?;

        // Update the base projector with rotated components
        // Note: We need to transpose back since components are stored as columns
        let rotated_components = rotation_result.rotated_loadings.t().to_owned();

        // Update the existing base projector with the rotated components
        self.base_projector.set_projection_matrix(rotated_components)?;

        // If rotation is oblique, we need to handle it differently
        if !rotation_result.is_orthogonal {
            // For oblique rotations, the explained variance interpretation changes
            // We should add a warning or handle this case specially
            log::warn!("Oblique rotation applied. Explained variance ratios may no longer be directly interpretable.");
        }

        Ok(())
    }

    /// Get the scores (transformed data) for the fitted model
    /// 
    /// This is equivalent to calling `transform` on the training data
    /// but may be more efficient if the scores were cached during fitting.
    pub fn scores(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.transform(data)
    }

    /// Compute influence measures for observations
    /// 
    /// Returns a matrix where each row contains:
    /// - Column 0: Leverage (hat values)
    /// - Column 1: Cook's distance
    /// - Column 2: DFFITS
    /// 
    /// These measures help identify influential observations that have a large effect
    /// on the PCA model.
    pub fn influence_measures(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let n_samples = data.nrows();
        let scores = self.transform(data)?;
        let eigenvalues = self.explained_variance()?;

        // Initialize result matrix
        let mut measures = Matrix::zeros((n_samples, 3));

        // Compute leverage (hat values) for each observation
        // h_i = sum(score_ij^2 / (n * eigenvalue_j))
        for i in 0..n_samples {
            let mut leverage = 0.0;
            for j in 0..self.n_components() {
                if eigenvalues[j] > 1e-10 {
                    leverage += (scores[[i, j]] * scores[[i, j]]) / ((n_samples as f64) * eigenvalues[j]);
                }
            }
            measures[[i, 0]] = leverage;
        }

        // Compute residuals for Cook's distance and DFFITS
        let q_residuals = self.q_residuals(data)?;
        let mean_q = q_residuals.mean().unwrap_or(0.0);

        // Estimate residual variance
        let mut residual_variance = 0.0;
        for i in 0..n_samples {
            residual_variance += (q_residuals[i] - mean_q).powi(2);
        }
        residual_variance /= (n_samples - self.n_components() - 1) as f64;

        // Compute Cook's distance and DFFITS
        for i in 0..n_samples {
            let leverage = measures[[i, 0]];

            // Cook's distance: D_i = (r_i^2 / p) * (h_i / (1 - h_i)^2)
            // where r_i is the standardized residual and p is the number of components
            if residual_variance > 1e-10 && leverage < 0.999 {
                let std_residual = q_residuals[i] / residual_variance.sqrt();
                let cooks_d = (std_residual * std_residual / self.n_components() as f64) * 
                             (leverage / ((1.0 - leverage) * (1.0 - leverage)));
                measures[[i, 1]] = cooks_d;

                // DFFITS: DFFITS_i = r_i * sqrt(h_i / (1 - h_i))
                let dffits = std_residual * (leverage / (1.0 - leverage)).sqrt();
                measures[[i, 2]] = dffits;
            }
        }

        Ok(measures)
    }

    /// Compute model fit statistics
    /// 
    /// Returns a struct containing various fit statistics:
    /// - Total variance explained
    /// - Residual sum of squares (RSS)
    /// - R-squared value
    /// - Adjusted R-squared
    /// - Root mean square error (RMSE)
    /// - Akaike Information Criterion (AIC)
    /// - Bayesian Information Criterion (BIC)
    pub fn fit_statistics(&self, data: &Matrix) -> Result<PcaFitStatistics, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let n_samples = data.nrows();
        let n_features = data.ncols();
        let n_components = self.n_components();

        // Compute residuals
        let transformed = self.transform(data)?;
        let reconstructed = self.inverse_transform(&transformed)?;
        let residuals = data - &reconstructed;

        // Residual sum of squares
        let rss = residuals.iter().map(|&x| x * x).sum::<f64>();

        // Total sum of squares (using preprocessed data)
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        let mut tss = 0.0;
        for j in 0..n_features {
            let col_mean = preprocessed.column(j).mean().unwrap_or(0.0);
            for i in 0..n_samples {
                let diff = preprocessed[[i, j]] - col_mean;
                tss += diff * diff;
            }
        }

        // R-squared
        let r_squared = if tss > 1e-10 { 1.0 - (rss / tss) } else { 0.0 };

        // Adjusted R-squared
        let df_resid = (n_samples * n_features - n_components * (n_samples + n_features)) as f64;
        let df_total = (n_samples * n_features - 1) as f64;
        let adj_r_squared = if df_total > 0.0 && df_resid > 0.0 {
            1.0 - ((1.0 - r_squared) * df_total / df_resid)
        } else {
            r_squared
        };

        // Root mean square error
        let rmse = (rss / (n_samples * n_features) as f64).sqrt();

        // Log-likelihood for AIC/BIC (assuming Gaussian errors)
        let sigma_squared = rss / (n_samples * n_features) as f64;
        let log_likelihood = -0.5 * (n_samples * n_features) as f64 * 
                            (1.0 + (2.0 * std::f64::consts::PI * sigma_squared).ln());

        // Number of parameters: components * (samples + features)
        let n_params = n_components * (n_samples + n_features);

        // AIC = 2k - 2ln(L)
        let aic = 2.0 * n_params as f64 - 2.0 * log_likelihood;

        // BIC = ln(n)*k - 2ln(L)
        let bic = (n_samples * n_features) as f64 * n_params as f64 - 2.0 * log_likelihood;

        Ok(PcaFitStatistics {
            total_variance_explained: self.total_variance_explained(),
            residual_sum_of_squares: rss,
            r_squared,
            adjusted_r_squared: adj_r_squared,
            rmse,
            aic,
            bic,
            n_components,
            n_samples,
            n_features,
        })
    }
}

// Implement projection traits
impl Project for Pca {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.transform(data)
    }

    fn n_components(&self) -> usize {
        self.base_projector.n_components()
    }

    fn n_features(&self) -> usize {
        self.base_projector.n_features()
    }

    fn is_fitted(&self) -> bool {
        self.base_projector.is_fitted()
    }

    fn name(&self) -> &str {
        "PCA"
    }
}

impl Reconstruct for Pca {
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
        self.inverse_transform(projected)
    }
}

impl PartialProject for Pca {
    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Apply preprocessing
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        // Use base projector for partial projection
        self.base_projector.project_components(&preprocessed, component_indices)
    }

    fn component_importance(&self) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        Ok(self.explained_variance_ratio.clone())
    }
}

impl fmt::Display for Pca {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        if self.is_fitted() {
            write!(
                f,
                "PCA(n_components={}, n_features={}, method={:?}, variance_explained={:.2}%)",
                self.n_components(),
                self.n_features(),
                self.svd_method,
                self.total_variance_explained() * 100.0
            )
        } else {
            write!(f, "PCA(unfitted)")
        }
    }
}

/// Builder for PCA
#[derive(Debug, Clone)]
pub struct PcaBuilder {
    config: PcaConfig,
}

impl PcaBuilder {
    pub fn new() -> Self {
        Self {
            config: PcaConfig::default(),
        }
    }

    /// Set the number of components
    pub fn n_components(mut self, n: usize) -> Self {
        self.config.projector_config.n_components = Some(n);
        self
    }

    /// Set minimum variance to retain
    pub fn min_variance(mut self, ratio: f64) -> Self {
        self.config.min_variance_retained = Some(ratio);
        self
    }

    /// Use correlation matrix instead of covariance
    pub fn use_correlation(mut self, use_corr: bool) -> Self {
        self.config.use_correlation = use_corr;
        self
    }

    /// Set SVD method
    pub fn svd_method(mut self, method: SvdMethod) -> Self {
        self.config.svd_method = method;
        self
    }

    /// Set whether to center data
    pub fn center(mut self, center: bool) -> Self {
        self.config.projector_config.center = center;
        self
    }

    /// Set whether to scale data
    pub fn scale(mut self, scale: bool) -> Self {
        self.config.projector_config.scale = scale;
        self
    }

    /// Set random state for reproducibility
    pub fn random_state(mut self, seed: u64) -> Self {
        self.config.projector_config.random_state = Some(seed);
        self.config.svd_config.random_state = Some(seed);
        self
    }

    /// Build the PCA instance
    pub fn build(self) -> Pca {
        Pca::new(self.config)
    }
}

impl Default for PcaBuilder {
    fn default() -> Self {
        Self::new()
    }
}

