    #[test]
    fn test_pca_basic() {
        // Create simple data with clear principal components
        let data = array![
            [1.0, 2.0],
            [2.0, 4.0],
            [3.0, 6.0],
            [4.0, 8.0],
            [5.0, 10.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(1)
            .build();

        pca.fit(&data).unwrap();

        // Check that we have 1 component
        assert_eq!(pca.n_components(), 1);
        assert_eq!(pca.n_features(), 2);

        // Transform the data
        let transformed = pca.transform(&data).unwrap();
        assert_eq!(transformed.shape(), &[5, 1]);

        // Check explained variance (should be ~100% for this perfectly correlated data)
        assert!(pca.total_variance_explained() > 0.99);
    }

    #[test]
