            [10.0, 11.0, 12.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();

        let transformed = pca.fit_transform(&data).unwrap();
        let reconstructed = pca.inverse_transform(&transformed).unwrap();

        // Check shapes
        assert_eq!(transformed.shape(), &[4, 2]);
        assert_eq!(reconstructed.shape(), &[4, 3]);

        // With 2 components out of 3, reconstruction should be pretty good
        let error = pca.reconstruction_error(&data).unwrap();
