        pca.fit(&data).unwrap();

        // Test explained variance
        let explained_var = pca.explained_variance().unwrap();
        assert_eq!(explained_var.len(), 4);
        assert!(explained_var[0] > explained_var[1]); // First component should have most variance

        // Test n_components_for_variance
        let n_comps = pca.n_components_for_variance(0.95).unwrap();
        assert!(n_comps >= 1 && n_comps <= 4);

        // Test variance explained by subset
        let var_subset = pca.variance_explained_by_components(&[0, 1]).unwrap();
        assert!(var_subset > 0.0 && var_subset <= 1.0);
        assert!(var_subset <= pca.total_variance_explained());

        // Test standard deviations
        let sdevs = pca.standard_deviations();
        assert_eq!(sdevs.len(), 4);
        for i in 0..sdevs.len() {
            assert!((sdevs[i] * sdevs[i] - explained_var[i]).abs() < 1e-10);
        }

        // Test total variance
        assert!(pca.total_variance() > 0.0);
    }

