//! 
//! Varimax rotation maximizes the variance of squared loadings within components.
//! This tends to produce a simple structure where each variable loads highly on
//! one component and has small loadings on others.
//! 
//! # R Compatibility
//! 
//! This implementation is equivalent to R's `varimax()` function with `normalize = TRUE`.
//! 
//! ```R
//! # In R:
//! rotated <- varimax(loadings, normalize = TRUE)
//! ```
//! 
//! # References
//! 
//! Kaiser, H. F. (1958). The varimax criterion for analytic rotation in factor analysis.
//! Psychometrika, 23(3), 187-200.

use super::{Rotation, OrthogonalRotation, RotationResult, RotationConfig};
use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use ndarray::Array2;

/// Varimax rotation method
/// 
/// Varimax is an orthogonal rotation method that maximizes the sum of variances
/// of squared loadings within components. This creates a "simple structure" where
/// each variable tends to load highly on one component and have near-zero loadings
/// on others, making interpretation easier.
/// 
/// # Example
/// 
/// ```
/// use multivarious::pca::{PcaBuilder, VarimaxRotation};
/// use ndarray::array;
/// 
/// let data = array![
///     [1.0, 2.0, 0.1, 0.2],
///     [2.0, 3.0, 0.2, 0.1],
///     [0.1, 0.2, 3.0, 4.0],
///     [0.2, 0.1, 4.0, 5.0],
/// ];
/// 
/// let mut pca = PcaBuilder::new()
///     .n_components(2)
///     .build();
/// pca.fit(&data).unwrap();
/// 
/// // Apply varimax rotation
/// let rotation = VarimaxRotation::new();
/// let result = pca.rotate(&rotation).unwrap();
/// 
/// // The rotated loadings will have a simpler structure
/// println!("Rotated loadings:\n{:?}", result.rotated_loadings);
/// ```
#[derive(Debug, Clone)]
pub struct VarimaxRotation {
    config: RotationConfig,
}

